TILES_34: List[str] = [
    *[f"B{i}" for i in range(1, 10)],
    *[f"T{i}" for i in range(1, 10)],
    *[f"M{i}" for i in range(1, 10)],
    "E", "S", "W", "N", "P", "F", "D",
]
TILE_TO_ID: Dict[str, int] = {tile: i for i, tile in enumerate(TILES_34)}
ID_TO_TILE: Dict[int, str] = {i: tile for i, tile in enumerate(TILES_34)}
HONOR_IDS = set(range(27, 34))
TERMINAL_IDS = {0, 8, 9, 17, 18, 26}


class QNetwork(nn.Module):
    def __init__(self, input_dim: int = 139, hidden_dim: int = 256, output_dim: int = 34):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(input_dim, hidden_dim),
            nn.ReLU(),
            nn.Linear(hidden_dim, hidden_dim),
            nn.ReLU(),
            nn.Linear(hidden_dim, hidden_dim // 2),
            nn.ReLU(),
            nn.Linear(hidden_dim // 2, output_dim),
        )

    def forward(self, x):
        return self.net(x)


@dataclass
class Transition:
    state: np.ndarray
    action: int
    reward: float
    next_state: np.ndarray
    done: bool
    action_mask: np.ndarray
    next_action_mask: np.ndarray


class ReplayBuffer:
    def __init__(self, capacity: int = 20000):
        self.buffer: Deque[Transition] = deque(maxlen=capacity)

    def push(self, *args):
        self.buffer.append(Transition(*args))

    def sample(self, batch_size: int) -> List[Transition]:
        return random.sample(self.buffer, batch_size)

    def __len__(self) -> int:
        return len(self.buffer)


def hand_to_counts(hand: Sequence[str]) -> np.ndarray:
    counts = np.zeros(34, dtype=np.float32)
    for tile in hand:
        idx = TILE_TO_ID.get(tile)
        if idx is not None:
            counts[idx] += 1.0
    return counts


def melds_to_counts(melds: Sequence[Sequence[str]]) -> np.ndarray:
    counts = np.zeros(34, dtype=np.float32)
    for meld in melds:
        for tile in meld:
            idx = TILE_TO_ID.get(tile)
            if idx is not None:
                counts[idx] += 1.0
    return counts


def tile_neighbors(tile_id: int) -> List[int]:
    if tile_id >= 27:
        return []
    suit = tile_id // 9
    num = tile_id % 9
    out = []
    for d in (-2, -1, 1, 2):
        n = num + d
        if 0 <= n < 9:
            out.append(suit * 9 + n)
    return out


def count_pairs_triplets(counts: np.ndarray) -> Tuple[int, int]:
    pairs = int(np.sum(counts >= 2))
    triplets = int(np.sum(counts >= 3))
    return pairs, triplets


def isolated_score(counts: np.ndarray, tile_id: int) -> float:
    c = counts[tile_id]
    if c <= 0:
        return -999.0
    score = 0.0
    if tile_id in HONOR_IDS:
        score += 2.5
        if c >= 2:
            score -= 2.0 * c
        return score
    if tile_id in TERMINAL_IDS:
        score += 1.0
    neighbors = tile_neighbors(tile_id)
    support = sum(counts[n] for n in neighbors)
    if support == 0:
        score += 3.0
    elif support <= 1:
        score += 1.0
    score -= min(c - 1, 2) * 2.0
    suit = tile_id // 9
    num = tile_id % 9
    left = suit * 9 + max(0, num - 1)
    right = suit * 9 + min(8, num + 1)
    if left != tile_id:
        score -= 0.6 * counts[left]
    if right != tile_id:
        score -= 0.6 * counts[right]
    return score


class MahjongFeatureEncoder:
    input_dim = 139

    def encode(self, obs: Dict) -> np.ndarray:
        hand = obs.get("hand", [])
        melds = obs.get("melds", [])
        other_players = obs.get("other_players", [])
        hand_counts = hand_to_counts(hand)
        meld_counts = melds_to_counts(melds)
        discards_counts = np.zeros(34, dtype=np.float32)
        opp_meld_counts = np.zeros(34, dtype=np.float32)
        opp_riichi = np.zeros(3, dtype=np.float32)
        total_discards = np.zeros(3, dtype=np.float32)

        for i, p in enumerate(other_players[:3]):
            opp_riichi[i] = 1.0 if p.get("riichi", False) else 0.0
            total_discards[i] = float(len(p.get("discards", []))) / 30.0
            for tile in p.get("discards", []):
                idx = TILE_TO_ID.get(tile)
                if idx is not None:
                    discards_counts[idx] += 1.0
            for meld in p.get("melds", []):
                for tile in meld:
                    idx = TILE_TO_ID.get(tile)
                    if idx is not None:
                        opp_meld_counts[idx] += 1.0

        last_draw = np.zeros(34, dtype=np.float32)
        ld = obs.get("last_draw")
        if ld in TILE_TO_ID:
            last_draw[TILE_TO_ID[ld]] = 1.0

        scalar = np.array([
            1.0 if obs.get("riichi", False) else 0.0,
            1.0 if obs.get("can_riichi", False) else 0.0,
            len(hand) / 14.0,
            len(melds) / 4.0,
            float(np.sum(discards_counts)) / 60.0,
        ], dtype=np.float32)

        remaining_est = np.clip(4.0 - hand_counts - meld_counts - discards_counts - opp_meld_counts, 0.0, 4.0) / 4.0

        features = np.concatenate([
            hand_counts / 4.0,
            meld_counts / 4.0,
            discards_counts / 4.0,
            opp_meld_counts / 4.0,
            last_draw,
            opp_riichi,
            total_discards,
            scalar,
            remaining_est,
        ]).astype(np.float32)
        return features

    def legal_action_mask(self, hand: Sequence[str]) -> np.ndarray:
        counts = hand_to_counts(hand)
        return (counts > 0).astype(np.float32)


class HeuristicMahjongHelper:
    @staticmethod
    def is_complete_hand(tiles: List[str]) -> bool:
        counter = Counter(tiles)

        def can_form_sets(cntr: Counter) -> bool:
            if not cntr:
                return True
            tile = next(iter(cntr))
            if cntr[tile] >= 3:
                cntr[tile] -= 3
                if cntr[tile] == 0:
                    del cntr[tile]
