                seq = [f"{suit}{num + i}" for i in range(3)]
                if num <= 7 and all(cntr.get(t, 0) >= 1 for t in seq):
                    for t in seq:
                        cntr[t] -= 1
                        if cntr[t] == 0:
                            del cntr[t]
                    if can_form_sets(cntr):
                        return True
                    for t in seq:
                        cntr[t] = cntr.get(t, 0) + 1
            return False

        for tile in list(counter):
            if counter[tile] >= 2:
                counter[tile] -= 2
                if counter[tile] == 0:
                    del counter[tile]
                if can_form_sets(counter.copy()):
                    return True
                counter[tile] = counter.get(tile, 0) + 2
        return False

    @classmethod
    def effective_tiles_count(cls, hand: Sequence[str]) -> int:
        total = 0
        base = list(hand)
        for t in TILES_34:
            if cls.is_complete_hand(base + [t]):
                total += 1
        return total

    @classmethod
    def estimate_shanten_like(cls, hand: Sequence[str]) -> float:
        counts = hand_to_counts(hand)
        pairs, triplets = count_pairs_triplets(counts)
        sequences = 0
        mutable = counts.copy()
        for base in [0, 9, 18]:
            for i in range(base, base + 7):
                while mutable[i] > 0 and mutable[i + 1] > 0 and mutable[i + 2] > 0:
                    mutable[i] -= 1
                    mutable[i + 1] -= 1
                    mutable[i + 2] -= 1
                    sequences += 1
        meld_like = triplets + sequences
        taatsu = 0
        for base in [0, 9, 18]:
            for i in range(base, base + 8):
                taatsu += 1 if mutable[i] > 0 and mutable[i + 1] > 0 else 0
            for i in range(base, base + 7):
                taatsu += 1 if mutable[i] > 0 and mutable[i + 2] > 0 else 0
        need_meld = max(0, 4 - meld_like)
        need_pair = 0 if pairs > 0 else 1
        score = need_meld * 2 + need_pair - min(taatsu, need_meld)
        return float(max(-1, score))

    @classmethod
    def heuristic_discard_scores(cls, obs: Dict) -> np.ndarray:
        hand = obs.get("hand", [])
        counts = hand_to_counts(hand)
        scores = np.full(34, -1e9, dtype=np.float32)
        danger = np.zeros(34, dtype=np.float32)
        for p in obs.get("other_players", []):
            if p.get("riichi", False):
                for t in p.get("discards", []):
                    idx = TILE_TO_ID.get(t)
                    if idx is not None:
                        danger[idx] -= 0.8
                danger += 0.2
        for tile in set(hand):
            idx = TILE_TO_ID[tile]
            temp = list(hand)
            temp.remove(tile)
            shanten_like = cls.estimate_shanten_like(temp)
            eff = cls.effective_tiles_count(temp)
            iso = isolated_score(counts, idx)
            pair_bonus = 0.7 if counts[idx] >= 2 else 0.0
            if idx in HONOR_IDS and counts[idx] == 1:
                pair_bonus -= 0.5
            scores[idx] = (
                -2.5 * shanten_like
                + 0.35 * eff
                + iso
                - pair_bonus
                + danger[idx]
            )
        return scores


class DQNTrainer:
    def __init__(
        self,
        model: QNetwork,
        lr: float = 1e-3,
        gamma: float = 0.99,
        batch_size: int = 64,
        target_update: int = 200,
        device: str = "cpu",
    ):
        if torch is None:
            raise ImportError("PyTorch is required for training.")
        self.device = torch.device(device)
        self.model = model.to(self.device)
        self.target = QNetwork(input_dim=model.net[0].in_features).to(self.device)
        self.target.load_state_dict(self.model.state_dict())
        self.target.eval()
        self.optimizer = optim.Adam(self.model.parameters(), lr=lr)
        self.gamma = gamma
        self.batch_size = batch_size
        self.target_update = target_update
        self.buffer = ReplayBuffer()
        self.steps = 0

    def act(self, state: np.ndarray, mask: np.ndarray, epsilon: float) -> int:
        legal = np.flatnonzero(mask > 0)
        if len(legal) == 0:
            return 0
        if random.random() < epsilon:
            return int(random.choice(legal))
        with torch.no_grad():
            x = torch.tensor(state, dtype=torch.float32, device=self.device).unsqueeze(0)
            q = self.model(x).squeeze(0).cpu().numpy()
            q[mask <= 0] = -1e9
            return int(np.argmax(q))

    def push(self, *args):
        self.buffer.push(*args)

    def train_step(self) -> Optional[float]:
        if len(self.buffer) < self.batch_size:
            return None
        batch = self.buffer.sample(self.batch_size)
        states = torch.tensor(np.stack([b.state for b in batch]), dtype=torch.float32, device=self.device)
        actions = torch.tensor([b.action for b in batch], dtype=torch.long, device=self.device)
        rewards = torch.tensor([b.reward for b in batch], dtype=torch.float32, device=self.device)
        next_states = torch.tensor(np.stack([b.next_state for b in batch]), dtype=torch.float32, device=self.device)
        dones = torch.tensor([b.done for b in batch], dtype=torch.float32, device=self.device)
        next_masks = torch.tensor(np.stack([b.next_action_mask for b in batch]), dtype=torch.float32, device=self.device)

        q_values = self.model(states).gather(1, actions.unsqueeze(1)).squeeze(1)
        with torch.no_grad():
            next_online = self.model(next_states)
            next_online[next_masks <= 0] = -1e9
            next_actions = next_online.argmax(dim=1)
            next_target = self.target(next_states).gather(1, next_actions.unsqueeze(1)).squeeze(1)
            targets = rewards + self.gamma * (1.0 - dones) * next_target

        loss = nn.SmoothL1Loss()(q_values, targets)
        self.optimizer.zero_grad()
        loss.backward()
        nn.utils.clip_grad_norm_(self.model.parameters(), 5.0)
        self.optimizer.step()

        self.steps += 1
        if self.steps % self.target_update == 0:
            self.target.load_state_dict(self.model.state_dict())
        return float(loss.item())

    def save(self, path: str):
        torch.save(self.model.state_dict(), path)


class RLMahjongAgent(MahjongAgent):
    """
    Hybrid RL Mahjong discard agent.

    - Inference uses a DQN if weights are available.
    - Falls back to a strong heuristic policy when weights are absent.
    - Always returns legal actions matching the required interface.
    """

    def __init__(
        self,
        model_path: Optional[str] = None,
        device: str = "cpu",
        rl_weight: float = 0.65,
        heuristic_weight: float = 0.35,
        use_rule_fallback: bool = True,
        seed: Optional[int] = 42,
    ):
        self.encoder = MahjongFeatureEncoder()
        self.helper = HeuristicMahjongHelper()
        self.device = device
        self.rl_weight = rl_weight
        self.heuristic_weight = heuristic_weight
        self.use_rule_fallback = use_rule_fallback
        self.model_path = model_path or os.path.join(os.path.dirname(__file__), "rl_mahjong_model.pth")
        self.rng = random.Random(seed)
        self.model = None
        self.has_trained_model = False
        if torch is not None:
            self.model = QNetwork(input_dim=self.encoder.input_dim, output_dim=34)
            if os.path.exists(self.model_path):
                try:
                    state = torch.load(self.model_path, map_location=device)
                    self.model.load_state_dict(state)
                    self.model.eval()
                    self.has_trained_model = True
                except Exception:
                    self.model = QNetwork(input_dim=self.encoder.input_dim, output_dim=34)
                    self.has_trained_model = False

    def _rule_select(self, obs: Dict) -> str:
        hand = obs.get("hand", [])
        if not hand:
            return ""
        scores = self.helper.heuristic_discard_scores(obs)
        legal = [TILE_TO_ID[t] for t in hand if t in TILE_TO_ID]
        best = max(legal, key=lambda i: (scores[i], -i))
        return ID_TO_TILE[best]

    def _rl_q_values(self, obs: Dict) -> Optional[np.ndarray]:
        if not self.has_trained_model or self.model is None or torch is None:
            return None
        state = self.encoder.encode(obs)
        with torch.no_grad():
            x = torch.tensor(state, dtype=torch.float32).unsqueeze(0)
            q = self.model(x).squeeze(0).cpu().numpy().astype(np.float32)
        return q

    def select_tile(self, obs: Dict) -> str:
        hand = obs.get("hand", [])
        if not hand:
            return ""
        mask = self.encoder.legal_action_mask(hand)
        legal = np.flatnonzero(mask > 0)
        if len(legal) == 1:
            return ID_TO_TILE[int(legal[0])]

        heuristic_scores = self.helper.heuristic_discard_scores(obs)
        q = self._rl_q_values(obs)
        if q is None:
            return self._rule_select(obs)

        q[mask <= 0] = -1e9
        heuristic_scores[mask <= 0] = -1e9
        q_norm = self._normalize_scores(q)
        h_norm = self._normalize_scores(heuristic_scores)
        combined = self.rl_weight * q_norm + self.heuristic_weight * h_norm
        best = int(np.argmax(combined))
        if mask[best] <= 0 and self.use_rule_fallback:
            return self._rule_select(obs)
        return ID_TO_TILE[best]

    @staticmethod
    def _normalize_scores(scores: np.ndarray) -> np.ndarray:
        finite = scores[np.isfinite(scores)]
        if finite.size == 0:
            return np.zeros_like(scores)
        lo = float(np.min(finite))
        hi = float(np.max(finite))
        if math.isclose(lo, hi):
            out = np.zeros_like(scores)
            out[np.isfinite(scores)] = 0.5
            return out
        out = np.zeros_like(scores)
        out[np.isfinite(scores)] = (scores[np.isfinite(scores)] - lo) / (hi - lo)
        return out

    def act(self, obs: Dict) -> Dict:
        hand = obs.get("hand", [])
        if not hand:
            return {"type": "discard", "tile": ""}
        tile = self.select_tile(obs)
        if tile not in hand:
            tile = hand[0]
        action_type = "riichi_discard" if obs.get("can_riichi", False) and self._should_riichi(obs, tile) else "discard"
        return {"type": action_type, "tile": tile}

    def _should_riichi(self, obs: Dict, tile: str) -> bool:
        if obs.get("riichi", False):
            return False
        hand = list(obs.get("hand", []))
        if tile not in hand:
