def can_form_sets(counter):
    if not counter:
        return True

    tile = next(iter(counter))

    if counter[tile] >= 3:
        counter[tile] -= 3
        if counter[tile] == 0:
            del counter[tile]
        if can_form_sets(counter):
            return True
        counter[tile] = counter.get(tile, 0) + 3

