        if not hand:
            return ""
        scores = self.helper.heuristic_discard_scores(obs)
        legal = [TILE_TO_ID[t] for t in hand if t in TILE_TO_ID]
        best = max(legal, key=lambda i: (scores[i], -i))
        return ID_TO_TILE[best]

    def _rl_q_values(self, obs: Dict) -> Optional[np.ndarray]:
        if not self.has_trained_model or self.model is None or torch is None:
            return None
        state = self.encoder.encode(obs)
        with torch.no_grad():
            x = torch.tensor(state, dtype=torch.float32).unsqueeze(0)
            q = self.model(x).squeeze(0).cpu().numpy().astype(np.float32)
        return q

    def select_tile(self, obs: Dict) -> str:
        hand = obs.get("hand", [])
        if not hand:
            return ""
        mask = self.encoder.legal_action_mask(hand)
        legal = np.flatnonzero(mask > 0)
        if len(legal) == 1:
            return ID_TO_TILE[int(legal[0])]

        heuristic_scores = self.helper.heuristic_discard_scores(obs)
        q = self._rl_q_values(obs)
        if q is None:
            return self._rule_select(obs)

        q[mask <= 0] = -1e9
        heuristic_scores[mask <= 0] = -1e9
        q_norm = self._normalize_scores(q)
        h_norm = self._normalize_scores(heuristic_scores)
        combined = self.rl_weight * q_norm + self.heuristic_weight * h_norm
        best = int(np.argmax(combined))
        if mask[best] <= 0 and self.use_rule_fallback:
            return self._rule_select(obs)
        return ID_TO_TILE[best]

    @staticmethod
    def _normalize_scores(scores: np.ndarray) -> np.ndarray:
        finite = scores[np.isfinite(scores)]
        if finite.size == 0:
            return np.zeros_like(scores)
        lo = float(np.min(finite))
        hi = float(np.max(finite))
        if math.isclose(lo, hi):
            out = np.zeros_like(scores)
            out[np.isfinite(scores)] = 0.5
            return out
        out = np.zeros_like(scores)
        out[np.isfinite(scores)] = (scores[np.isfinite(scores)] - lo) / (hi - lo)
        return out

    def act(self, obs: Dict) -> Dict:
        hand = obs.get("hand", [])
        if not hand:
            return {"type": "discard", "tile": ""}
        tile = self.select_tile(obs)
        if tile not in hand:
            tile = hand[0]
        action_type = "riichi_discard" if obs.get("can_riichi", False) and self._should_riichi(obs, tile) else "discard"
        return {"type": action_type, "tile": tile}

    def _should_riichi(self, obs: Dict, tile: str) -> bool:
        if obs.get("riichi", False):
            return False
        hand = list(obs.get("hand", []))
        if tile not in hand:
            return False
        hand.remove(tile)
        return self.helper.effective_tiles_count(hand) > 0


